import React, { useState, useRef, useEffect } from 'react';
import { ChevronLeft, ChevronRight, X, Lock, Eye, Play, Shield, Gavel, Volume2, VolumeX, ArrowLeft } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { useUser } from '../contexts/UserContext';

interface CaseData {
  title: string;
  caseNumber: string;
  leftPage: string;
  rightPage: string;
}

const ScenarioSimulation: React.FC = () => {
  const [opened, setOpened] = useState(false);
  const [currentPage, setCurrentPage] = useState(0);
  const [isFlipping, setIsFlipping] = useState(false);
  const [rotation, setRotation] = useState({ x: 0, y: 0 });
  const [showEntryAnimation, setShowEntryAnimation] = useState(true);
  const [unlockProgress, setUnlockProgress] = useState(0);
  const [isUnlocked, setIsUnlocked] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [currentSpeech, setCurrentSpeech] = useState<'left' | 'right' | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const speechSynthesisRef = useRef<SpeechSynthesisUtterance | null>(null);
  const navigate = useNavigate();
  const { user } = useUser();

  // Entry animation effect
  useEffect(() => {
    if (showEntryAnimation) {
      const timer = setTimeout(() => {
        setShowEntryAnimation(false);
      }, 3000);
      return () => clearTimeout(timer);
    }
  }, [showEntryAnimation]);

  // Unlock progress effect
  useEffect(() => {
    if (unlockProgress < 100 && !isUnlocked) {
      const timer = setTimeout(() => {
        setUnlockProgress(prev => Math.min(prev + 10, 100));
      }, 200);
      return () => clearTimeout(timer);
    } else if (unlockProgress === 100) {
      setIsUnlocked(true);
    }
  }, [unlockProgress, isUnlocked]);

  // Cleanup speech on unmount
  useEffect(() => {
    return () => {
      if (speechSynthesisRef.current && window.speechSynthesis.speaking) {
        window.speechSynthesis.cancel();
      }
    };
  }, []);

  const caseData: CaseData[] = [
    {
      title: 'CASE FILE #001',
      caseNumber: 'RK-2025-001',
      leftPage: `笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊申nCASE FILE #001 - LEFT PAGE
