    // Stop any ongoing speech when flipping pages
    if (window.speechSynthesis.speaking) {
      window.speechSynthesis.cancel();
      setIsSpeaking(false);
      setCurrentSpeech(null);
    }

    if (isFlipping) return;

    setIsFlipping(true);
