        <div className="flex justify-between text-xs text-gray-400 mt-1">
          <span>File {currentPage + 1} of {caseData.length}</span>
          <span>{progressPercentage}% Complete</span>
        </div>
      </div>

      {/* Book Container */}
      <div className="flex-1 bg-gradient-to-b from-gray-800 to-gray-900 flex items-center justify-center px-8 py-6 gap-6" style={{ minHeight: 'calc(100vh - 200px)' }}>
        {/* Left Page */}
        <div className={`w-1/2 h-full bg-yellow-50 rounded-lg shadow-2xl p-10 overflow-y-auto transition-all duration-500 transform ${isFlipping ? 'opacity-50 -translate-x-12 rotate-y-45' : 'opacity-100 translate-x-0'} hover:shadow-pink-500/50 relative`} style={{ maxHeight: '70vh' }}>
          <div className="text-gray-800 text-xs leading-relaxed font-mono whitespace-pre-wrap select-text">
            {caseData[currentPage].leftPage}
          </div>
          <div className="mt-8 pt-4 border-t-2 border-gray-400 text-center">
            <span className="text-xs text-gray-500 font-mono">Page {currentPage * 2 + 1}</span>
          </div>

          {/* Voice Control for Left Page */}
          {isSpeechSupported && (
            <div className="absolute top-4 right-4">
              <button
                onClick={() => speakText(caseData[currentPage].leftPage, 'left')}
                disabled={isSpeaking && currentSpeech !== 'left'}
                className={`p-2 rounded-full ${isSpeaking && currentSpeech === 'left' ? 'bg-red-500 text-white' : 'bg-gray-200 text-gray-800'} hover:bg-gray-300 transition`}
                title={isSpeaking && currentSpeech === 'left' ? "Stop speaking" : "Read aloud"}
              >
                {isSpeaking && currentSpeech === 'left' ? <VolumeX size={20} /> : <Volume2 size={20} />}
              </button>
            </div>
          )}
        </div>

        {/* Right Page */}
        <div className={`w-1/2 h-full bg-yellow-50 rounded-lg shadow-2xl p-10 overflow-y-auto transition-all duration-500 transform ${isFlipping ? 'opacity-50 translate-x-12 -rotate-y-45' : 'opacity-100 translate-x-0'} hover:shadow-pink-500/50 relative`} style={{ maxHeight: '70vh' }}>
          <div className="text-gray-800 text-xs leading-relaxed font-mono whitespace-pre-wrap select-text">
            {caseData[currentPage].rightPage}
          </div>
          <div className="mt-8 pt-4 border-t-2 border-gray-400 text-center">
            <span className="text-xs text-gray-500 font-mono">Page {currentPage * 2 + 2}</span>
          </div>

          {/* Voice Control for Right Page */}
          {isSpeechSupported && (
            <div className="absolute top-4 right-4">
              <button
                onClick={() => speakText(caseData[currentPage].rightPage, 'right')}
                disabled={isSpeaking && currentSpeech !== 'right'}
                className={`p-2 rounded-full ${isSpeaking && currentSpeech === 'right' ? 'bg-red-500 text-white' : 'bg-gray-200 text-gray-800'} hover:bg-gray-300 transition`}
                title={isSpeaking && currentSpeech === 'right' ? "Stop speaking" : "Read aloud"}
              >
                {isSpeaking && currentSpeech === 'right' ? <VolumeX size={20} /> : <Volume2 size={20} />}
              </button>
            </div>
          )}
        </div>
      </div>

      {/* Navigation Footer */}
      <div className="bg-gradient-to-r from-gray-800 to-gray-700 p-6 rounded-b-xl flex items-center justify-between border-t-4 border-pink-600 sticky bottom-0">
        <button
          onClick={() => flipPage('prev')}
          disabled={currentPage === 0 || isFlipping}
          className="flex items-center gap-2 px-8 py-3 bg-pink-500 hover:bg-pink-600 disabled:bg-gray-600 disabled:cursor-not-allowed text-white rounded-lg transition font-bold transform hover:scale-105"
        >
          <ChevronLeft size={24} />
          Previous
        </button>

        <div className="text-center text-white">
          <p className="text-xl font-bold">File {currentPage + 1} of {caseData.length}</p>
          <p className="text-sm text-gray-400">Double Page Spread 窶｢ Pages {currentPage * 2 + 1}-{currentPage * 2 + 2}</p>
        </div>

        <button
          onClick={() => flipPage('next')}
          disabled={currentPage === caseData.length - 1 || isFlipping}
          className="flex items-center gap-2 px-8 py-3 bg-pink-500 hover:bg-pink-600 disabled:bg-gray-600 disabled:cursor-not-allowed text-white rounded-lg transition font-bold transform hover:scale-105"
        >
          Next
          <ChevronRight size={24} />
        </button>
      </div>
    </div>
  );
};

export default ScenarioSimulation;
